def make():
    keys = random.sample(["a", "b", "c", "d", "e"], random.randint(3, 4))
    vals = random.sample(range(1, 9), len(keys))
    d = dict(zip(keys, vals))
    starter = "def invert(d):\n    # your code here\n    pass"
    solution = "def invert(d):\n    return {v: k for k, v in d.items()}"
    inverted = {v: k for k, v in d.items()}
    tests = "assert invert(" + repr(d) + ") == " + repr(inverted)
    return {"starter": starter, "solution": solution, "tests": tests}
